+    Managed,
+}
+
+impl Default for RerankerDispatch {
+    fn default() -> Self {
+        Self::Disabled
+    }
+}
+
+impl RerankerDispatch {
+    /// Canonical string representation.
+    #[must_use]
+    pub fn as_str(self) -> &'static str {
+        match self {
+            Self::Disabled => "disabled",
+            Self::Legacy => "legacy",
+            Self::Managed => "managed",
+        }
+    }
